// Derives the worker's logo assets from the single source of truth:
// assets/logo.svg (edit it freely — any SVG works). Run
// `node scripts/generate-logo-assets.mjs` after changing it; the script
// rewrites packages/gw-worker/src/logo.generated.ts with the embedded SVG
// string and a 16x16 favicon (PNG-in-ICO, rasterized with resvg).
// Never edit the generated file by hand.
import { readFileSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";
import { Resvg } from "@resvg/resvg-js";

/** Wrap a PNG in an ICO container (the Vista+ PNG-in-ICO format). */
function pngToIco(png, size) {
  const buf = Buffer.alloc(22 + png.length);
  buf.writeUInt16LE(1, 2); // type: icon
  buf.writeUInt16LE(1, 4); // image count
  buf.writeUInt8(size, 6);
  buf.writeUInt8(size, 7);
  buf.writeUInt16LE(1, 10); // planes
  buf.writeUInt16LE(32, 12); // bpp
  buf.writeUInt32LE(png.length, 14);
  buf.writeUInt32LE(22, 18); // data offset
  png.copy(buf, 22);
  return buf;
}

function main() {
  const root = join(dirname(fileURLToPath(import.meta.url)), "..");
  const svg = readFileSync(join(root, "assets/logo.svg"), "utf8");
  const png = new Resvg(svg, { fitTo: { mode: "width", value: 16 } }).render().asPng();
  const ico = pngToIco(Buffer.from(png), 16);
  const gen =
    "// GENERATED by scripts/generate-logo-assets.mjs — do not edit.\n" +
    "// Source of truth: assets/logo.svg.\n" +
    `export const LOGO_SVG = ${JSON.stringify(svg.trim())};\n` +
    `export const FAVICON_ICO_B64 = ${JSON.stringify(ico.toString("base64"))};\n`;
  writeFileSync(join(root, "packages/gw-worker/src/logo.generated.ts"), gen);
  console.log(`embedded logo.svg (${svg.length}B), favicon ${ico.length}B`);
}

const isDirectRun = import.meta.url === `file://${process.argv[1]}`;
if (isDirectRun) main();
